import Anthropic from '@anthropic-ai/sdk';

const client = new Anthropic({
  apiKey: process.env.ANTHROPIC_API_KEY,
  timeout: 30 * 1000,  // milliseconds
  maxRetries: 2,
});

// Async/await — all methods return Promises
const message = await client.messages.create({
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  messages: [{ role: 'user', content: 'Hello' }],
});

console.log(message.content[0].text);

// Direct HTTP approach for Go when SDK beta lags
package main

import (
    "bytes"
    "encoding/json"
    "fmt"
    "net/http"
    "os"
)

func main() {
    body, _ := json.Marshal(map[string]interface{}{
        "model":      "claude-haiku-4-5-20251001",
        "max_tokens": 1024,
        "messages": []map[string]string{
            {"role": "user", "content": "Hello"},
        },
    })

    req, _ := http.NewRequest("POST",
        "https://api.anthropic.com/v1/messages",
        bytes.NewBuffer(body))
    req.Header.Set("x-api-key", os.Getenv("ANTHROPIC_API_KEY"))
    req.Header.Set("anthropic-version", "2023-06-01")
    req.Header.Set("content-type", "application/json")

    resp, _ := http.DefaultClient.Do(req)
    defer resp.Body.Close()
    // decode resp.Body into struct...
    fmt.Println(resp.Status)
}

import Anthropic from '@anthropic-ai/sdk';

const client = new Anthropic();

const stream = client.messages.stream({
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  messages: [{ role: 'user', content: 'Write a haiku about TypeScript.' }],
});

// Async iteration over text deltas
for await (const text of stream.textStream) {
  process.stdout.write(text);
}
console.log();

const finalMessage = await stream.finalMessage();
console.log('Stop reason:', finalMessage.stop_reason);

import pytest
import os

# conftest.py
def pytest_configure(config):
    config.addinivalue_line(
        "markers", "integration: marks tests as integration tests (require ANTHROPIC_API_KEY)"
    )

def pytest_collection_modifyitems(config, items):
    if not os.environ.get("ANTHROPIC_API_KEY"):
        skip_integration = pytest.mark.skip(reason="ANTHROPIC_API_KEY not set")
        for item in items:
            if "integration" in item.keywords:
                item.add_marker(skip_integration)

# test_integration.py
@pytest.mark.integration
def test_real_api_call():
    import anthropic
    client = anthropic.Anthropic()
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=10,
        messages=[{"role": "user", "content": "Say only 'OK'."}]
    )
    assert "OK" in response.content[0].text
